// === IoT Telemetry Processor ===
// Purpose: Process each telemetry event, track per-device stats,
// and return human-readable summary for the dashboard.

const body = $json.body || $json;
const deviceId = body.device_id || 'unknown';
const temp = Number(body.temperature) || 0;
const humidity = Number(body.humidity) || 0;

// Determine alert status
let alertStatus = 'normal';
if (temp > 45) alertStatus = 'critical';
else if (temp > 35) alertStatus = 'warning';

// Alert icons
const icon = alertStatus === 'critical' ? '\uD83D\uDEA8' :
             alertStatus === 'warning' ? '\u26A0\uFE0F' : '\u2705';

// Build human-readable summary
const summaries = {
  'normal': `${icon} Device \"${deviceId}\": Suhu ${temp}\u00B0C — Normal. Tidak ada tindakan diperlukan.`,
  'warning': `${icon} Device \"${deviceId}\": Suhu ${temp}\u00B0C, Kelembapan ${humidity}% — Melebihi batas normal. Perlu dipantau.`,
  'critical': `${icon} Device \"${deviceId}\": Suhu ${temp}\u00B0C, Kelembapan ${humidity}% — CRITICAL! Butuh tindakan segera!`
};

const summary = summaries[alertStatus];

// Track per-device stats
let deviceStats = {};
try {
  deviceStats = $workflow.variables.get('deviceStats') || {};
} catch(e) {
  deviceStats = {};
}

if (!deviceStats[deviceId]) {
  deviceStats[deviceId] = {
    count: 0,
    firstSeen: new Date().toISOString(),
    alerts: { normal: 0, warning: 0, critical: 0 }
  };
}

deviceStats[deviceId].count += 1;
deviceStats[deviceId].lastTemp = temp;
deviceStats[deviceId].lastAlert = alertStatus;
deviceStats[deviceId].lastSeen = new Date().toISOString();
deviceStats[deviceId].alerts[alertStatus] += 1;

try {
  $workflow.variables.set('deviceStats', deviceStats);
} catch(e) {
  // workflow variables not available
}

return [{
  json: {
    alertStatus: alertStatus,
    summary: summary,
    device_id: deviceId,
    temperature: temp,
    humidity: humidity,
    n8n_processed_at: new Date().toISOString()
  }
}];
